#include<bits/stdc++.h>
#define ll long long
#define CI const int
using namespace std;
CI MAXN=1e2+5;int n,a[MAXN][MAXN];
int main(void){
	scanf("%d",&n);
    for(int i=1;i<=n;++i){
    	for(int j=1;j<=n;++j){
        	scanf("%d",&a[i][j]);
            if(!a[i][j])a[i][j]=0x3f3f3f3f;
		}
	}for(int k=1;k<=n;++k)
        for(int i=1;i<=n;++i)
            for(int j=1;j<=n;++j)
                a[i][j]=min(a[i][k]+a[k][j],a[i][j]);
    for(int i=1;i<=n;++i){
        for(int j=1;j<=n;++j)
        	if(a[i][j]==0x3f3f3f3f)printf("0 ");
        	else printf("1 ");
        printf("\n");
    }return false;
}
